
-- crypto_pages
CREATE TABLE public.crypto_pages (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  slug text NOT NULL UNIQUE,
  title text NOT NULL,
  h1 text NOT NULL,
  meta_title text NOT NULL DEFAULT '',
  meta_description text NOT NULL DEFAULT '',
  keyword text NOT NULL DEFAULT '',
  intro_text text NOT NULL DEFAULT '',
  content text NOT NULL DEFAULT '',
  partner_url text NOT NULL DEFAULT '',
  priority integer NOT NULL DEFAULT 0,
  published boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);
GRANT SELECT ON public.crypto_pages TO anon;
GRANT SELECT ON public.crypto_pages TO authenticated;
GRANT ALL ON public.crypto_pages TO service_role;
ALTER TABLE public.crypto_pages ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public can read published crypto pages"
  ON public.crypto_pages FOR SELECT
  USING (published = true);
CREATE POLICY "Admins manage crypto pages"
  ON public.crypto_pages FOR ALL
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'))
  WITH CHECK (public.has_role(auth.uid(), 'admin'));
CREATE TRIGGER update_crypto_pages_updated_at
  BEFORE UPDATE ON public.crypto_pages
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

