  partner_url text NOT NULL DEFAULT '',
  priority integer NOT NULL DEFAULT 0,
  published boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);
GRANT SELECT ON public.ai_pages TO anon;
GRANT SELECT ON public.ai_pages TO authenticated;
GRANT ALL ON public.ai_pages TO service_role;
ALTER TABLE public.ai_pages ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public can read published ai pages"
  ON public.ai_pages FOR SELECT
  USING (published = true);
CREATE POLICY "Admins manage ai pages"
  ON public.ai_pages FOR ALL
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'))
  WITH CHECK (public.has_role(auth.uid(), 'admin'));
CREATE TRIGGER update_ai_pages_updated_at
  BEFORE UPDATE ON public.ai_pages
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- Seed: crypto_pages
INSERT INTO public.crypto_pages (slug, title, h1, meta_title, meta_description, keyword, intro_text, content, priority) VALUES
('obmenniki',
 'Лучшие обменники криптовалюты в 2026 году',
 'Лучшие обменники криптовалюты в 2026 году',
 'Лучшие обменники криптовалюты в 2026 году — обзор EraPay',
 'Как выбрать надёжный обменник криптовалюты в 2026 году: на что смотреть в резервах, отзывах и курсах, какие риски бывают.',
 'обменники криптовалюты',
 'Обменники криптовалюты — сервисы, где можно быстро купить или продать крипту по фиксированному курсу без ордеров и стаканов. Они удобны для небольших сумм и разовых операций, но требуют внимательности при выборе.',
 '<p>Обменник — это витрина, за которой стоит оператор, обменивающий вашу фиату на криптовалюту (или обратно) по своему курсу. В отличие от биржи, здесь нет книги заявок: вы видите итоговую цену, курс, комиссию и через 10–30 минут получаете актив на кошелёк.</p><p>Ключевые критерии выбора обменника — прозрачность резервов, срок работы, отзывы на независимых мониторингах (BestChange, Kurs.expert), понятная процедура KYC для крупных сумм и адекватная поддержка. Курс всегда чуть хуже биржевого — это плата за скорость и простоту.</p><p>Красные флаги: обещание «курса лучше рынка», отсутствие юридического лица, единственный канал связи в Telegram, требование переводить средства «на карту сотрудника». Не переводите крупные суммы новым обменникам без репутации.</p><p>Для больших операций эффективнее пользоваться P2P на крупных биржах или OTC-столами — курс будет ближе к рыночному. Обменник — про удобство и скорость, а не про экономию.</p><p>Помните: покупка криптовалюты не запрещена в РФ, но она не является средством платежа и не защищена государственными гарантиями. Все операции — на ваш риск.</p>',
 6),
('kupit-usdt',
 'Где купить USDT за рубли в 2026 году',
 'Где купить USDT за рубли в 2026 году',
 'Где купить USDT за рубли в 2026 году — обзор EraPay',
 'Способы легально купить USDT за рубли: P2P на биржах, обменники, банковские переводы. Плюсы, минусы и комиссии каждого способа.',
 'купить usdt за рубли',
 'USDT (Tether) — стейблкоин, курс которого привязан к доллару США. Это один из самых востребованных активов в СНГ: им расплачиваются с фрилансерами, хранят сбережения от волатильности и переводят деньги за рубеж.',
 '<p>Купить USDT за рубли можно тремя основными способами: через P2P-сервисы на криптобиржах (Bybit, MEXC, HTX), через классические обменники и через специализированные приложения. Каждый способ имеет свой курс, скорость и уровень риска.</p><p><strong>P2P на бирже.</strong> Самый выгодный курс, но требует времени: нужно найти продавца с хорошим рейтингом, перевести рубли на его карту/СБП и дождаться разморозки USDT. Комиссии почти нулевые, но иногда банки задают вопросы о переводе.</p><p><strong>Обменник.</strong> Быстро и просто: вы указываете реквизиты, отправляете рубли, через 10–30 минут получаете USDT. Курс на 1–3% хуже P2P, но не нужно самому взаимодействовать с продавцом. Выбирайте только обменники из топа BestChange.</p><p><strong>Сеть перевода.</strong> USDT существует в разных сетях: TRC-20 (Tron) — дешёвая и быстрая, ERC-20 (Ethereum) — дорогая, но универсальная, TON, BEP-20 (BSC), Solana. Убедитесь, что кошелёк-получатель поддерживает выбранную сеть, иначе средства будут потеряны.</p><p>Что нужно учитывать: банки в РФ имеют право приостанавливать операции по 115-ФЗ, если видят подозрительный характер платежей. Не переводите крупные суммы одной транзакцией с назначением «покупка криптовалюты» — это привлекает внимание.</p>',
 5),
('birzhi',
 'Лучшие криптовалютные биржи для россиян в 2026 году',
 'Лучшие криптовалютные биржи для россиян в 2026 году',
 'Криптовалютные биржи для россиян в 2026 году — сравнение',
 'Какие криптобиржи работают с россиянами в 2026 году: комиссии, KYC, P2P, вывод в рубли. Обзор EraPay.',
 'криптобиржи для россиян',
 'Криптовалютные биржи — площадки, где можно торговать десятками пар, использовать плечо, стейкать активы и покупать крипту через P2P. Для россиян выбор бирж сузился, но остались несколько крупных игроков.',
 '<p>По состоянию на 2026 год россияне активно пользуются несколькими биржами: Bybit, MEXC, HTX (бывший Huobi), Gate.io, KuCoin. Binance для граждан РФ ограничена — часть функций недоступна или требует смены резидентства. OKX также сузил присутствие для российских паспортов.</p><p><strong>Bybit.</strong> Одна из самых удобных бирж для СНГ: развитый P2P с рублями, приятный интерфейс, широкий список пар. KYC базового уровня достаточно для большинства операций.</p><p><strong>MEXC.</strong> Много альткоинов, простая регистрация, работает P2P. Меньше ликвидности на низкоприоритетных парах, но для основных монет всё есть.</p><p><strong>HTX и Gate.io.</strong> Крупные азиатские биржи, обе поддерживают рубли в P2P, дают доступ к деривативам и стейкингу.</p><p>Что важно: с 2024 года мировые биржи усилили комплаенс. Верифицируйте аккаунт заранее, храните доказательства происхождения средств, не переводите крупные суммы без подготовки. И помните: биржа — не банк, средства на ней не застрахованы. Активы, которые вы не собираетесь торговать в ближайшее время, разумнее хранить на собственном кошельке.</p>',
 4),
('koshelki',
 'Лучшие криптокошельки в 2026 году',
 'Лучшие криптокошельки в 2026 году',
 'Лучшие криптокошельки 2026 — обзор EraPay',
 'Как выбрать криптокошелёк: горячие и холодные, аппаратные и мобильные. Обзор популярных решений в 2026 году.',
 'криптокошельки',
 'Криптокошелёк — программа или устройство, которое хранит ваши приватные ключи и позволяет отправлять и получать монеты. Правило простое: не ваши ключи — не ваши монеты. На бирже вы владеете лишь обещанием биржи выдать актив.',
 '<p>Кошельки делятся на две большие категории: горячие (подключены к интернету) и холодные (offline). Горячие удобны для повседневных операций, холодные — для хранения крупных сумм.</p><p><strong>Горячие мобильные и десктопные:</strong> Trust Wallet, MetaMask, Phantom (для Solana), Rabby, Exodus. Устанавливаются как обычное приложение, поддерживают десятки сетей и DeFi-подключения через WalletConnect.</p><p><strong>Аппаратные (холодные):</strong> Ledger Nano S/X, Trezor Model T, Keystone, SafePal. Ключи хранятся на устройстве и никогда не покидают его. Для перевода вы физически подтверждаете транзакцию кнопкой на кошельке. Оптимальный вариант для сумм от нескольких тысяч долларов.</p><p><strong>Правила безопасности:</strong> seed-фраза (12 или 24 слова) — это ключ ко всем вашим активам. Никогда не вводите её в компьютер, не фотографируйте, не храните в облаке. Оптимально — записать на бумаге или металлической пластине и убрать в сейф.</p><p>Отдельно упомянем встроенные кошельки в мессенджерах (Telegram Wallet, TON Space) — они удобны, но по сути это кастодиальные сервисы, где ключи хранит оператор. Для крупных сумм это неподходящий вариант.</p>',
 3),
('p2p-vs-obmennik',
 'P2P или обменник: как выгоднее купить крипту',
 'P2P или обменник: как выгоднее купить крипту',
 'P2P или обменник — что выбрать при покупке криптовалюты',
 'Сравнение P2P на биржах и классических обменников: курсы, скорость, риски, комиссии. Что выбрать для разных сумм.',
 'p2p или обменник',
 'Два самых популярных способа купить криптовалюту за рубли — P2P на бирже и обменник. Оба работают, оба легальны, но подходят для разных задач. Разбираем, когда какой выгоднее.',
 '<p><strong>P2P (Peer-to-Peer).</strong> На бирже (Bybit, HTX, MEXC) вы выбираете продавца из списка объявлений, переводите ему рубли напрямую на карту или через СБП, и биржа автоматически разблокирует крипту с эскроу-счёта. Курс близок к рыночному, комиссия почти нулевая.</p><p><strong>Обменник.</strong> Вы отправляете рубли по реквизитам обменника, он присылает вам крипту на кошелёк. Быстро и просто, но курс на 1–3% хуже P2P — это заработок обменника.</p><p><strong>Скорость.</strong> Обменник обычно быстрее: 10–30 минут против часа-двух на P2P (зависит от того, как быстро отвечает продавец).</p><p><strong>Риски.</strong> В P2P основной риск — банковский: контрагент может пожаловаться после получения крипты, и вашу карту заблокируют по 115-ФЗ. Поэтому важно указывать назначение «перевод физлицу без указания цели» (а не «покупка крипты») и работать только с продавцами с высоким рейтингом. В обменнике риск — недобросовестный оператор: если контора без репутации исчезнет, деньги не вернуть.</p><p><strong>Итог.</strong> Для сумм до 50–100 тыс. ₽ обменник удобнее — простота решает. Для больших сумм и регулярных операций выгоднее P2P: экономия на курсе становится ощутимой. И всегда сверяйте курс с BestChange перед сделкой.</p>',
 2),
('vyvod-v-rubli',
 'Как вывести криптовалюту в рубли без блокировки карты',
 'Как вывести криптовалюту в рубли без блокировки карты',
 'Как безопасно вывести криптовалюту в рубли',
 'Способы вывода криптовалюты в рубли и как избежать блокировки банковской карты по 115-ФЗ. Практическое руководство EraPay.',
 'как вывести криптовалюту в рубли',
 'Вывод криптовалюты в рубли — обратная операция покупке, но именно она чаще всего приводит к вопросам от банка. Разбираем, как минимизировать риск блокировки карты по 115-ФЗ и какие способы существуют.',
 '<p><strong>Почему банк может заблокировать карту.</strong> Федеральный закон 115-ФЗ обязывает банки контролировать «подозрительные» операции. Регулярные крупные поступления от разных физлиц, привязанные к криптосделкам, — типичный триггер. Банк имеет право приостановить операции и запросить документы, подтверждающие источник средств.</p><p><strong>Основные способы вывода:</strong></p><ul><li><strong>P2P на бирже.</strong> Вы продаёте USDT или другую крипту покупателю за рубли, он переводит вам на карту. Курс лучший, но с точки зрения банка вы получаете деньги от постороннего физлица.</li><li><strong>Обменник.</strong> Отправляете крипту, обменник переводит рубли на карту. Юридическое лицо-обменник в назначении платежа выглядит для банка приличнее.</li><li><strong>Через криптокарту.</strong> Некоторые сервисы дают дебетовые карты, привязанные к балансу в USDT (Bybit Card и др.). Оплата в магазинах или снятие в банкомате конвертирует крипту в фиату автоматически.</li></ul><p><strong>Как снизить риск блокировки:</strong> не выводите большие суммы одной операцией; распределяйте поступления между несколькими картами и банками; сохраняйте историю сделок с биржи; не используйте карту, привязанную к зарплатному проекту; будьте готовы предоставить банку выписку с биржи и объяснить источник средств.</p><p><strong>Легальность.</strong> Владение и обмен криптовалюты в РФ не запрещены. Криптовалюта признана имуществом. Однако она не является средством платежа, и оплата ей товаров/услуг внутри страны недопустима. Доход от операций подлежит декларированию и уплате НДФЛ.</p>',
 1);

